#include <string.h>
#include <sys/wait.h>

/* == EXEMPLE =======================================
 * Ping-pong avec un entier via 2 pipes
 * p2c: parent envoie 42, c2p: enfant renvoie 42+1
 * ================================================= */
void example_bidir(void) {
    int p2c[2], c2p[2];
    pipe(p2c); pipe(c2p);
    if (fork() == 0) {
        close(p2c[1]); close(c2p[0]);
        int v; read(p2c[0], &v, sizeof(v));
        v++;
        write(c2p[1], &v, sizeof(v));
        close(p2c[0]); close(c2p[1]);
        _exit(0);
    }
    close(p2c[0]); close(c2p[1]);
    int val = 42;
    write(p2c[1], &val, sizeof(val));
    close(p2c[1]);
    read(c2p[0], &val, sizeof(val));
    printf("Got back: %d\n", val);
    close(c2p[0]); wait(NULL);
}
